import { describe, expect, it } from "vitest";
import { parseQuery } from "../src/parseQuery.js";

// Every test names the concrete bug it would catch. Expected values are
// computed by hand from the doc comment in src/parseQuery.js, not by running
// the implementation.

describe("parseQuery — basic key/value", () => {
  it("maps a single key to its string value", () => {
    // Catches: value returned as something other than the plain string.
    expect(parseQuery("a=1")).toEqual({ a: "1" });
  });

  it("keeps values as strings, not numbers", () => {
    // Catches: accidental Number() coercion of numeric-looking values.
    const result = parseQuery("n=42");
    expect(result.n).toBe("42");
  });

  it("parses multiple distinct keys", () => {
    // Catches: only first/last pair kept; "&" splitting broken.
    expect(parseQuery("a=1&b=2&c=3")).toEqual({ a: "1", b: "2", c: "3" });
  });

  it("keeps only the substring before the first '=' as the key", () => {
    // Catches: splitting on every "=" instead of the first one.
    expect(parseQuery("a=b=c")).toEqual({ a: "b=c" });
  });

  it("maps 'key=' (empty value after '=') to an empty string", () => {
    // Catches: empty value dropped or turned into undefined.
    expect(parseQuery("a=")).toEqual({ a: "" });
  });
});

describe("parseQuery — leading '?'", () => {
  it("strips a single leading '?'", () => {
    // Catches: "?" treated as part of the first key.
    expect(parseQuery("?a=1&b=2")).toEqual({ a: "1", b: "2" });
  });

  it("strips only ONE leading '?', keeping the second", () => {
    // Catches: stripping all leading "?" instead of exactly one.
    expect(parseQuery("??a=1")).toEqual({ "?a": "1" });
  });

  it("does not strip a '?' that is not leading", () => {
    // Catches: over-eager "?" removal from values.
    expect(parseQuery("a=?")).toEqual({ a: "?" });
  });
});

describe("parseQuery — bare keys (no '=')", () => {
  it("maps a bare key to an empty string", () => {
    // Catches: bare key mapped to null/undefined/true instead of "".
    expect(parseQuery("flag")).toEqual({ flag: "" });
  });

  it("maps several bare keys each to an empty string", () => {
    // Catches: only one bare key surviving.
    expect(parseQuery("a&b&c")).toEqual({ a: "", b: "", c: "" });
  });

  it("mixes bare keys with valued keys", () => {
    // Catches: bare/valued mix mis-parsed.
    expect(parseQuery("a=1&flag&b=2")).toEqual({ a: "1", flag: "", b: "2" });
  });
});

describe("parseQuery — empty segments", () => {
  it("skips an empty segment between pairs ('a=1&&b=2')", () => {
    // Catches: empty "" key created from a doubled "&".
    expect(parseQuery("a=1&&b=2")).toEqual({ a: "1", b: "2" });
  });

  it("skips leading and trailing empty segments", () => {
    // Catches: stray "" key from a leading/trailing "&".
    expect(parseQuery("&a=1&")).toEqual({ a: "1" });
  });

  it("returns an empty object for an empty string", () => {
    // Catches: "" producing a {"": ""} entry.
    expect(parseQuery("")).toEqual({});
  });

  it("returns an empty object for just '?'", () => {
    // Catches: lone "?" producing a spurious key.
    expect(parseQuery("?")).toEqual({});
  });
});

describe("parseQuery — repeated keys become arrays", () => {
  it("collects two occurrences into an array in order", () => {
    // Catches: second value overwriting the first (last-wins bug).
    expect(parseQuery("a=1&a=2")).toEqual({ a: ["1", "2"] });
  });

  it("collects three occurrences preserving order", () => {
    // Catches: array built but order reversed, or third value lost.
    expect(parseQuery("a=1&a=2&a=3")).toEqual({ a: ["1", "2", "3"] });
  });

  it("does not wrap a single occurrence in an array", () => {
    // Catches: always-array bug — single key must stay a string.
    const result = parseQuery("a=1");
    expect(Array.isArray(result.a)).toBe(false);
    expect(result.a).toBe("1");
  });

  it("keeps interleaved duplicate values in appearance order", () => {
    // Catches: array grouping that ignores insertion order across keys.
    expect(parseQuery("a=1&b=2&a=3")).toEqual({ a: ["1", "3"], b: "2" });
  });

  it("groups repeated bare keys into an array of empty strings", () => {
    // Catches: duplicate bare keys collapsing to a single "".
    expect(parseQuery("x&x")).toEqual({ x: ["", ""] });
  });
});

describe("parseQuery — '+' becomes a space", () => {
  it("decodes '+' to a space in a value", () => {
    // Catches: "+" left literal in the value.
    expect(parseQuery("q=hello+world")).toEqual({ q: "hello world" });
  });

  it("decodes '+' to a space in a key", () => {
    // Catches: "+" replacement applied to values only, not keys.
    expect(parseQuery("first+name=John")).toEqual({ "first name": "John" });
  });

  it("decodes every '+' in a token, not just the first", () => {
    // Catches: replace() (first only) instead of replaceAll().
    expect(parseQuery("q=a+b+c")).toEqual({ q: "a b c" });
  });
});

describe("parseQuery — percent-decoding", () => {
  it("percent-decodes a space in a value", () => {
    // Catches: %20 left undecoded.
    expect(parseQuery("q=a%20b")).toEqual({ q: "a b" });
  });

  it("percent-decodes '=' inside a key (%3D)", () => {
    // Catches: keys not being decoded at all.
    expect(parseQuery("a%3Db=c")).toEqual({ "a=b": "c" });
  });

  it("decodes %2B to a literal '+' (no space)", () => {
    // Catches: order bug — if percent-decode ran before "+"→space,
    // the resulting "+" would wrongly become a space.
    expect(parseQuery("a=%2B")).toEqual({ a: "+" });
  });

  it("applies '+'→space first, then percent-decoding, in one token", () => {
    // Catches: wrong ordering when both "+" and "%xx" appear.
    // "1%2B1+equals" -> "1%2B1 equals" -> "1+1 equals".
    expect(parseQuery("q=1%2B1+equals")).toEqual({ q: "1+1 equals" });
  });

  it("percent-decodes multi-byte UTF-8 sequences", () => {
    // Catches: byte-wise decoding that mangles multi-byte chars.
    expect(parseQuery("name=%C3%A9")).toEqual({ name: "é" });
  });
});

describe("parseQuery — malformed percent-encoding falls back to raw", () => {
  it("uses the raw token when a lone '%' cannot be decoded", () => {
    // Catches: throwing on bad input instead of falling back.
    expect(parseQuery("a=100%")).toEqual({ a: "100%" });
  });

  it("uses the raw token for an invalid escape like '%zz'", () => {
    // Catches: crash on non-hex escape digits.
    expect(parseQuery("a=%zz")).toEqual({ a: "%zz" });
  });

  it("never throws on malformed input", () => {
    // Catches: an unguarded decodeURIComponent throwing URIError.
    expect(() => parseQuery("a=%&b=%E0%A4")).not.toThrow();
  });

  it("falls back after applying '+'→space when decode fails", () => {
    // Catches: fallback returning the pre-"+"-replacement token.
    // "%GG+x" -> "%GG x" (decode fails) -> raw "%GG x".
    expect(parseQuery("a=%GG+x")).toEqual({ a: "%GG x" });
  });
});

describe("parseQuery — empty-key edge cases", () => {
  it("maps a lone '=' to the empty key with an empty value", () => {
    // Catches: empty key silently dropped.
    expect(parseQuery("=")).toEqual({ "": "" });
  });

  it("groups repeated empty keys into an array", () => {
    // Catches: second "=" overwriting the empty-key entry.
    expect(parseQuery("=&=")).toEqual({ "": ["", ""] });
  });
});

